(() => {
  const BOOT_SOUND_DATA_URI = "data:audio/wav;base64,";
  const bootSound = new Audio(BOOT_SOUND_DATA_URI);
  bootSound.preload = "auto";

  function playBootSound() {
    if (!bootSound) return;

    bootSound.currentTime = 0;
    bootSound.play().catch(() => {
      // ignore autoplay failure silently
    });
  }

  window.DevSkitsBootSound = {
    playBootSound
  };
})();
